import React from 'react';
import clsx from 'clsx';
import { useDetailsDisplayContext } from './DetailsDisplayContext';
import { useDetailsDisplayItemContext } from './DetailsDisplayItemContext';
import { Text } from '../text';

const Content = () => {
  const { contentStyle: rootContentStyle, contentClassName: rootContentClassName } = useDetailsDisplayContext();
  const { contentStyle, contentClassName, content } = useDetailsDisplayItemContext();

  return (
    <Text style={{ ...rootContentStyle, ...contentStyle }} className={clsx(rootContentClassName, contentClassName)}>
      {content}
    </Text>
  );
};

export default Content;
